import re

def romanToInteger(romanLetters, romanNumber):
    alphabet = {}

    if len(set(romanLetters)) != len(romanLetters) or not romanLetters.isalpha() or romanNumber == "" or not romanLetters.isupper():
        return -9999

    counter_of_nulls = 1
    for i, char in enumerate(romanLetters):
        if i % 2 == 0:
            alphabet[char] = 1 * counter_of_nulls
        else:
            alphabet[char] = 5 * counter_of_nulls
            counter_of_nulls *= 10

    valid_roman_num_pattern = "^"
    len_roman_letters = len(romanLetters)
    counter = 0
    patterns_of_place_value = []
    while counter < len_roman_letters:
        pattern = "("

        if counter + 1 < len_roman_letters:
            pattern += f"{romanLetters[counter]}{romanLetters[counter + 1]}|{romanLetters[counter + 1]}" + "{0,1}"

        pattern += f"{romanLetters[counter]}" + "{0,3}"

        if counter + 2 < len_roman_letters:
            pattern += f"|{romanLetters[counter]}{romanLetters[counter + 2]}"
        pattern += ")"
        patterns_of_place_value.append(pattern)

        counter += 2

    for pattern in reversed(patterns_of_place_value):
        valid_roman_num_pattern += pattern
    valid_roman_num_pattern += "$"

    if re.fullmatch(valid_roman_num_pattern, romanNumber) is None:
        return -9999

    arabic_numb = 0
    counter = 0
    len_roman_number = len(romanNumber)
    while counter < len_roman_number:
        if counter + 1 < len_roman_number and alphabet[romanNumber[counter]] < alphabet[romanNumber[counter + 1]]:
            arabic_numb += alphabet[romanNumber[counter + 1]] - alphabet[romanNumber[counter]]
            counter += 2
        else:
            arabic_numb += alphabet[romanNumber[counter]]
            counter += 1

    return arabic_numb

def loadMap(file_oath):
    with open(file_oath, "r", encoding="utf-8") as f:
        lines = [line.rstrip("\n") for line in f.readlines()]
    height, width = len(lines), max(len(line) for line in lines) if lines else 0
    walls, storages, crates, sokoban = set(), set(), set(), None
    for y, riadok in enumerate(lines):
        for x, znak in enumerate(riadok):
            if znak == '#':
                walls.add((x, y))
            elif znak == 'X':
                storages.add((x, y))
            elif znak == 'C':
                crates.add((x, y))
            elif znak == 'S':
                sokoban = (x, y)
            elif znak == 's':
                sokoban = (x, y)
                storages.add((x, y))
            elif znak == 'c':
                crates.add((x, y))
                storages.add((x, y))
    return width, height, walls, storages, crates, sokoban

class CNFEncoder:
    def __init__(self):
        self.varId = {}
        self.idVar = [None]
        self.clauses = []
        self.comments = []

    def getVar(self, name):
        if name in self.varId:
            return self.varId[name]
        var_id = len(self.idVar)
        self.varId[name] = var_id
        self.idVar.append(name)
        return var_id

    def addClause(self, lits):
        if len(lits) == 0:
            self.clauses.append([0])
        else:
            self.clauses.append(list(lits))

    def addComment(self, text: str):
        self.comments.append(text)
        self.clauses.append(None)

    def writingDimacs(self, filename):
        num_vars = len(self.idVar) - 1
        num_clauses = sum(1 for c in self.clauses if c is not None)
        comment_index = 0
        with open(filename, "w", encoding="utf-8") as f:
            f.write("c CNF encoding for Sokoban SAT\n")
            f.write("c Variable mapping:\n")
            for i in range(1, len(self.idVar)):
                f.write(f"c {i} {self.idVar[i]}\n")
            f.write(f"p cnf {num_vars} {num_clauses}\n")
            for clause in self.clauses:
                if clause is None:
                    f.write(f"c --- {self.comments[comment_index]} ---\n")
                    comment_index += 1
                    continue
                if clause == [0]:
                    f.write("0\n")
                else:
                    line = " ".join(str(l) for l in clause) + " 0\n"
                    f.write(line)

    def writeHumanCNF(self, filename):
        def lit_to_str(lit):
            if isinstance(lit, str):
                return lit
            if lit == 0:
                return "---"
            idx = abs(lit)
            if idx >= len(self.idVar):
                name = f"VAR?({idx})"
            else:
                name = self.idVar[idx]
            return name if lit > 0 else f"-{name}"
        comment_index = 0
        written = 0
        with open(filename, "w", encoding="utf-8") as f:
            f.write("# Human-readable CNF\n")
            for clause in self.clauses:
                if clause is None:
                    f.write(f"\n### {self.comments[comment_index]} ###\n")
                    comment_index += 1
                    continue
                if clause == [0]:
                    f.write("---\n")
                else:
                    parts = [lit_to_str(l) for l in clause]
                    f.write(" v ".join(parts) + "\n")
                written += 1

def reachable_cells_without_crates(width, height, walls, start):
    if start is None:
        return set()
    sx, sy = start
    if (sx, sy) in walls:
        return set()
    q = deque([(sx, sy)])
    seen = {(sx, sy)}
    while q:
        x, y = q.popleft()
        for dx, dy in DIRECTS.values():
            nx, ny = x + dx, y + dy
            if 0 <= nx < width and 0 <= ny < height and (nx, ny) not in walls and (nx, ny) not in seen:
                seen.add((nx, ny))
                q.append((nx, ny))
    return seen

def buildCnf(map_file, n_steps):
    width, height, walls, storages, crates0, sokoban0 = loadMap(map_file)
    encoder = CNFEncoder()
    reachable = reachable_cells_without_crates(width, height, walls, sokoban0)
    cells = [(x, y) for (x, y) in reachable]
    cells_set = set(cells)
    if not cells:
        cells = [sokoban0] if sokoban0 else []
        cells_set = set(cells)
    sok_vv, crate_vv = {}, {}
    for t in range(n_steps + 1):
        for (x, y) in cells:
            sok_vv[(t, x, y)] = encoder.getVar(f"Sokoban({t},{x},{y})")
            crate_vv[(t, x, y)] = encoder.getVar(f"Crate({t},{x},{y})")
    move_vv, push_vv = {}, {}
    actionsT = {t: [] for t in range(n_steps)}
    def inside(nx, ny):
        return 0 <= nx < width and 0 <= ny < height
    def free_cell(nx, ny):
        return inside(nx, ny) and (nx, ny) not in walls and (nx, ny) in cells_set
    for t in range(n_steps):
        for (x, y) in cells:
            for dir_name, (dx, dy) in DIRECTS.items():
                x2, y2 = x + dx, y + dy
                if free_cell(x2, y2):
                    mv_id = encoder.getVar(f"Move({t},{x},{y},{dir_name})")
                    move_vv[(t, x, y, dir_name)] = mv_id
                    actionsT[t].append(mv_id)
                    x3, y3 = x2 + dx, y2 + dy
                    if free_cell(x3, y3):
                        ps_id = encoder.getVar(f"Push({t},{x},{y},{dir_name})")
                        push_vv[(t, x, y, dir_name)] = ps_id
                        actionsT[t].append(ps_id)
    encoder.addComment("Initial state")
    for (x, y) in cells:
        s0 = sok_vv[(0, x, y)]
        encoder.addClause([s0] if (x, y) == sokoban0 else [-s0])
        b0 = crate_vv[(0, x, y)]
        encoder.addClause([b0] if (x, y) in crates0 else [-b0])
    encoder.addComment("Sokoban and Crate cannot be in the same cell")
    for t in range(n_steps + 1):
        for (x, y) in cells:
            encoder.addClause([-sok_vv[(t, x, y)], -crate_vv[(t, x, y)]])
    encoder.addComment("Exactly one Sokoban position per timestep")
    for t in range(n_steps + 1):
        s_list = [sok_vv[(t, x, y)] for (x, y) in cells]
        encoder.addClause(s_list)
        for i in range(len(s_list)):
            for j in range(i + 1, len(s_list)):
                encoder.addClause([-s_list[i], -s_list[j]])
    encoder.addComment("Exactly one action per timestep")
    for t in range(n_steps):
        acts = actionsT[t]
        if not acts:
            encoder.addClause([])
            continue
        encoder.addClause(acts)
        for i in range(len(acts)):
            for j in range(i + 1, len(acts)):
                encoder.addClause([-acts[i], -acts[j]])
    encoder.addComment("Action preconditions and effects")
    for t in range(n_steps):
        for (tt, x, y, dir_name), mv in list(move_vv.items()):
            if tt != t:
                continue
            dx, dy = DIRECTS[dir_name]
            x2, y2 = x + dx, y + dy
            encoder.addClause([-mv, sok_vv[(t, x, y)]])
            encoder.addClause([-mv, -crate_vv[(t, x2, y2)]])
            encoder.addClause([-mv, sok_vv[(t + 1, x2, y2)]])
        for (tt, x, y, dir_name), ps in list(push_vv.items()):
            if tt != t:
                continue
            dx, dy = DIRECTS[dir_name]
            x2, y2 = x + dx, y + dy
            x3, y3 = x2 + dx, y2 + dy
            encoder.addClause([-ps, sok_vv[(t, x, y)]])
            encoder.addClause([-ps, crate_vv[(t, x2, y2)]])
            encoder.addClause([-ps, -crate_vv[(t, x3, y3)]])
            encoder.addClause([-ps, sok_vv[(t + 1, x2, y2)]])
            encoder.addClause([-ps, -crate_vv[(t + 1, x2, y2)]])
            encoder.addClause([-ps, crate_vv[(t + 1, x3, y3)]])
    encoder.addComment("Sokoban position must be justified by an action(no teleportation)")
    for t in range(n_steps):
        for (x2, y2) in cells:
            s_next = sok_vv[(t + 1, x2, y2)]
            actions_to_here = []
            for dir_name, (dx, dy) in DIRECTS.items():
                x1, y1 = x2 - dx, y2 - dy
                if (x1, y1) in cells_set:
                    mv = move_vv.get((t, x1, y1, dir_name))
                    if mv is not None:
                        actions_to_here.append(mv)
                    ps = push_vv.get((t, x1, y1, dir_name))
                    if ps is not None:
                        actions_to_here.append(ps)
            encoder.addClause([-s_next] + actions_to_here)
    encoder.addComment("Frame problem")
    for t in range(n_steps):
        for (x, y) in cells:
            b_t = crate_vv[(t, x, y)]
            b_next = crate_vv[(t + 1, x, y)]
            push_out = []
            push_in = []
            for dir_name, (dx, dy) in DIRECTS.items():
                x1, y1 = x - dx, y - dy
                ps = push_vv.get((t, x1, y1, dir_name))
                if ps is not None:
                    push_out.append(ps)
            for dir_name, (dx, dy) in DIRECTS.items():
                x2, y2 = x - dx, y - dy
                x1, y1 = x2 - dx, y2 - dy
                ps = push_vv.get((t, x1, y1, dir_name))
                if ps is not None:
                    push_in.append(ps)
            encoder.addClause([-b_t, b_next] + push_out)
            encoder.addClause([-b_next, b_t] + push_in)
    encoder.addComment("Goal state")
    for (x, y) in cells:
        if (x, y) not in storages:
            encoder.addClause([-crate_vv[(n_steps, x, y)]])
    return encoder, {"width": width, "height": height, "walls": walls, "storages": storages, "crates0": crates0, "sokoban0": sokoban0, "sok_vv": sok_vv, "crate_vv": crate_vv, "move_vv": move_vv, "push_vv": push_vv}

def runMinisat(cnf_file, result_file):
    try:
        proc = subprocess.run(["minisat", cnf_file, result_file], stdout=subprocess.PIPE, stderr=subprocess.PIPE, text=True)
    except FileNotFoundError:
        print("ERROR: minisat not found.")
        sys.exit(1)
    if not os.path.exists(result_file):
        print("Minisat didnt give a solution.")
        return "UNSAT", None
    with open(result_file, "r", encoding="utf-8") as f:
        lines = f.read().strip().split()
    if not lines or lines[0] == "UNSAT" or lines[0] != "SAT":
        return "UNSAT", None
    lits = []
    for i in lines[1:]:
        if i == "0":
            break
        lits.append(int(i))
    return "SAT", lits

def solutFromModel(encoder, lits, n_steps):
    true_vars = {l for l in lits if l > 0}
    id_to_name = encoder.idVar
    action_at_t = [None] * n_steps
    tempo_at_t = [None] * n_steps
    for lit in true_vars:
        name = id_to_name[lit]
        if not name:
            continue
        if name.startswith("Move(") or name.startswith("Push("):
            kind = "move" if name.startswith("Move(") else "push"
            inside = name[name.find("(") + 1:-1]
            parts = inside.split(",")
            if len(parts) < 4:
                continue
            try:
                t = int(parts[0])
            except ValueError:
                continue
            dir_name = parts[3]
            if 0 <= t < n_steps:
                if action_at_t[t] is None:
                    action_at_t[t] = (kind, dir_name)
                    tempo_at_t[t] = name
                else:
                    tempo_at_t[t] = f"{tempo_at_t[t]}  AND  {name}"
    solut = []
    tempo = []
    for t in range(n_steps):
        if action_at_t[t] is None:
            solut.append(("move", "up"))
            tempo.append("")
        else:
            solut.append(action_at_t[t])
            tempo.append(tempo_at_t[t])
    return solut, tempo

def vizual(map_file, solut):
    width, height, walls, storages, crates0, sokoban0 = loadMap(map_file)
    crates = set(crates0)
    sx, sy = sokoban0
    cratesT = {0: list(crates)}
    movesT = {0: [(sx, sy)]}
    for t, (kind, dir_name) in enumerate(solut, start=1):
        dx, dy = DIRECTS[dir_name]
        x2, y2 = sx + dx, sy + dy
        if (x2, y2) in walls:
            raise RuntimeError(f"Solution is invalid t={t} ({x2},{y2}).")
        if (x2, y2) in crates:
            x3, y3 = x2 + dx, y2 + dy
            if (x3, y3) in walls or (x3, y3) in crates:
                raise RuntimeError(f"Solution is invalid t={t} ({x2},{y2}).")
            crates.remove((x2, y2))
            crates.add((x3, y3))
        sx, sy = x2, y2
        cratesT[t] = list(crates)
        movesT[t] = [(sx, sy)]
    return {"walls": walls, "storages": storages, "crates": cratesT, "moves": movesT, "max_time": len(solut), "max_width": width, "max_height": height}

def solvedScreen(screen, clock, map_name, elapsed_seconds):
    font_title = pygame.font.SysFont("Arial", 34, bold=True)
    font_small = pygame.font.SysFont("Arial", 22)
    btn_font = pygame.font.SysFont("Arial", 24, bold=True)
    btn_w, btn_h = 320, 55
    btn_go = pygame.Rect((WINDOW_WIDTH - btn_w)//2, WINDOW_HEIGHT//2 + 40, btn_w, btn_h)
    btn_back = pygame.Rect((WINDOW_WIDTH - btn_w)//2, WINDOW_HEIGHT//2 + 110, btn_w, btn_h)
    while True:
        mouse_pos = pygame.mouse.get_pos()
        mouse_down = False
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                return "quit"
            if event.type == pygame.KEYDOWN:
                if event.key == pygame.K_RETURN:
                    return "go"
                if event.key == pygame.K_ESCAPE:
                    return "menu"
            if event.type == pygame.MOUSEBUTTONDOWN and event.button == 1:
                mouse_down = True
        screen.fill((255, 255, 255))
        drawCenteredText(screen, f"Map solved", font_title, WINDOW_HEIGHT//2 - 80, (0, 0, 0))
        drawCenteredText(screen, f"Map: {map_name}", font_small, WINDOW_HEIGHT//2 - 40, (0, 0, 0))
        drawCenteredText(screen, f"Time: {format_mmss(elapsed_seconds)}", font_small, WINDOW_HEIGHT//2 - 10, (0, 0, 0))
        if drawButton(screen, "Go to solution", btn_font, btn_go, mouse_pos, mouse_down):
            return "go"
        drawCenteredText(screen, "Enter - go, Esc - menu", pygame.font.SysFont("Arial", 18), WINDOW_HEIGHT - 25, (0, 0, 0))
        pygame.display.flip()
        clock.tick(30)
